import{_ as l,o as t,c as o,a as e}from"./chunks/plugin-vue_export-helper.B0FdOn3A.js";const d=JSON.parse('{"title":"Иерархия ценностей","description":"","frontmatter":{"title":"Иерархия ценностей","date":"2020-09-07T00:00:00.000Z"},"headers":[],"relativePath":"posts/2020-09-07-values-prioritization.md","filePath":"posts/2020-09-07-values-prioritization.md"}'),a={name:"posts/2020-09-07-values-prioritization.md"};function p(r,i,s,u,_,n){return t(),o("div",null,[...i[0]||(i[0]=[e('<p>В прошлом посте (<a href="/reflection.html">о рефлексии</a>) я рассказывал об упражнении на выявление своих потребностей и ценностей. Сегодня мы обогатим наш лексикон парой готовых фреймворков ценностей и приоритезируем наши нужды.</p><p>Первый фреймворк ценностей в нашем списке был создан в 1960-х Рене Доуисом и Ллойдом Лофкистом:</p><ul><li>Достижения - результаты и процесс</li><li>Комфорт - отсутствие стресса</li><li>Статус - признание и престиж</li><li>Альтруизм - гармоничное служение другим</li><li>Безопасность - предсказуемость и стабильность</li><li>Автономия - возможность управлять и инициативность</li></ul><p>В 2000-х Эдвард Дечи и Ричард Райан создали теорию Само-определения, она содержит всего три мотивирующих фактора, которые присущи всем человеческим существам:</p><ul><li>Компетенции - мастерство в своей сфере деятельности</li><li>Причастность - забота и контакт с окружающими</li><li>Автономия - управление, выбор, свобода</li></ul><p>Если вы выполнили упражнение в статье о Рефлексии, у вас уже есть некоторый список того, что важно именно вам, и это в тысячу раз более ценно, чем пользование готовыми системами. Фреймворки могут помочь обратить внимание на то, что вы, возможно упустили в самоанализе. Также список обычно увеличивается ответом на вопрос &quot;Почему вы делаете то, что вы делаете?&quot;</p><p>Можно использовать любую технику приоретизации, которая вам нравится. Если у вас нет такой техники, вот три на выбор:</p><ul><li>Прогрессивное вычеркивание - постепенно вычеркивайте то, от чего вы откажетесь не раздумывая, пункт за пунктом</li><li>Выбор - берем пункты попарно и выбираем один, потом берем ещё один пункт и выбираем снова</li><li>Категоризация - разместить пункты по категориям - критично, важно, желательно, опционально</li></ul><hr><p>Упражнение этого поста состоит в следующем:</p><ol start="0"><li>Выпишите ваши ценности в столбик, например: <ul><li>комфорт</li><li>справедливость</li><li>автономия</li><li>причастность</li><li>статус</li><li>востребованность навыков</li><li>перспективы - надежность и определенность</li><li>прогрессирующие трудности</li><li>деньги</li><li>возможность свободно креативить и самовыражаться</li><li>компетентность коллег</li></ul></li><li>Путем вычеркивания, выбора или категоризации, оставьте из них половину наиболее значимых</li><li>Внимательно изучите список и выберите три наиболее значимых. Взгляните ещё раз на график эмоций, который вы построили в прошлый раз. Что вызывало у вас самые положительные эмоции или самые отрицательные?</li></ol><p>Ещё один важный инструмент для само-определения - ранжирование. Любая ценность имеет свои &quot;слишком мало&quot; или &quot;слишком много&quot;. Есть определенное количество и качество аспекта, при котором всё хорошо. Например, ваш приоритет - общение с людьми. Но если вам предложат работу где вам нужно общаться с 1 человеком в месяц или с сотней в день, это вам вряд ли подойдёт. Поэтому важно понимать приемлемый уровень - минимум и максимум.</p><p>Ранжировав свои top-3 ценности, вы можете выбирать более подходящую вам рабочую роль и задавать на собеседовании вопросы, которые помогут сделать правильный выбор, с большей вероятностью ведущий к успеху и позитивным эмоциям.</p>',13)])])}const f=l(a,[["render",p]]);export{d as __pageData,f as default};
